<div class="card"><div class="page-title clearfix"><h1><?php echo app_lang('gd_school_attendance'); ?></h1></div><div class="card-body">
<?php echo form_open(get_uri('grupo_donato/school/attendance/save'),['id'=>'attendance-form','class'=>'general-form']); ?>
<div class="row"><div class="col-md-6"><label><?php echo app_lang('gd_school_class'); ?></label><?php echo form_dropdown('class_id',[''=>'-']+array_column($classes,'name','id'),'','id="attendance-class" class="form-control select2"'); ?></div><div class="col-md-4"><label><?php echo app_lang('gd_date'); ?></label><input id="attendance-date" name="date" type="date" class="form-control" value="<?php echo date('Y-m-d'); ?>"></div><div class="col-md-2 d-flex align-items-end"><button type="button" id="load-roster" class="btn btn-default w-100"><?php echo app_lang('gd_school_load_roster'); ?></button></div></div>
<div id="attendance-roster" class="mt-4"></div><?php if($can_manage): ?><button id="save-attendance" type="submit" class="btn btn-primary mt-3 hide"><?php echo app_lang('save'); ?></button><?php endif; ?><?php echo form_close(); ?></div></div>
<script>$(document).ready(function(){"use strict";$(".select2").select2();var canManage=<?php echo $can_manage?'true':'false'; ?>;var actions=canManage?'<div class="mb-2"><button type="button" id="mark-all-present" class="btn btn-sm btn-success me-1"><i data-feather="check-circle" class="icon-12"></i> <?php echo app_lang('gd_attendance_mark_all_present'); ?></button><button type="button" id="clear-marks" class="btn btn-sm btn-default"><?php echo app_lang('gd_attendance_clear'); ?></button></div>':'';function load(){var c=$("#attendance-class").val(),d=$("#attendance-date").val();if(!c||!d)return;$.getJSON('<?php echo_uri('grupo_donato/school/attendance/roster'); ?>',{class_id:c,date:d},function(r){if(!r.success)return appAlert.error(r.message);var t=r.data.totals,h='<div class="alert alert-light"><?php echo app_lang('gd_school_attendance_present'); ?>: '+t.present+' · <?php echo app_lang('gd_school_attendance_absent'); ?>: '+t.absent+' · <?php echo app_lang('gd_school_attendance_justified'); ?>: '+t.justified+' · <?php echo app_lang('gd_school_attendance_unmarked'); ?>: '+t.unmarked+'</div>'+actions+'<div class="table-responsive"><table class="table"><tr><th><?php echo app_lang('gd_school_student'); ?></th><th><?php echo app_lang('gd_status'); ?></th><th><?php echo app_lang('gd_notes'); ?></th></tr>';$.each(r.data.students,function(_,s){h+='<tr><td>'+s.full_name+'</td><td><select class="form-control" name="marks['+s.school_profile_id+'][status]"><option value="unmarked"><?php echo app_lang('gd_school_attendance_unmarked'); ?></option><option value="present"><?php echo app_lang('gd_school_attendance_present'); ?></option><option value="absent"><?php echo app_lang('gd_school_attendance_absent'); ?></option><option value="justified"><?php echo app_lang('gd_school_attendance_justified'); ?></option></select></td><td><input class="form-control" name="marks['+s.school_profile_id+'][notes]" value="'+(s.notes||'')+'"></td></tr>';});h+='</table></div>';$("#attendance-roster").html(h);$.each(r.data.students,function(_,s){$("[name='marks["+s.school_profile_id+"][status]']").val(s.attendance_status);});$("#save-attendance").removeClass('hide');});}$("#load-roster").click(load);$(document).on('click','#mark-all-present',function(){$("#attendance-roster select").val('present');});$(document).on('click','#clear-marks',function(){$("#attendance-roster select").val('unmarked');});$("#attendance-form").appForm({onSuccess:function(){load();}});});</script>
